class Solution:
    def minOperations(self, nums):
        nums = list(nums)
        n = len(nums)
        ops = 0
        for i in range(n - 2):
            if nums[i] == 0:
                nums[i] ^= 1
                nums[i+1] ^= 1
                nums[i+2] ^= 1
                ops += 1
        if nums[-1] == 0 or nums[-2] == 0:
            return -1
        return ops

