class Solution:
    def minOperations(self, nums):
        n = len(nums)
        ops = 0
        flip = 0  # running parity of flips applied
        flips = [0] * (n + 1)  # difference array
        for i in range(n - 2):
            flip ^= flips[i]
            cur = nums[i] ^ flip
            if cur == 0:
                ops += 1
                flip ^= 1
                flips[i + 3] ^= 1
        # check last two
        for i in range(n - 2, n):
            flip ^= flips[i]
            if nums[i] ^ flip == 0:
                return -1
        return ops

