var minOperations = function(nums) {
    const n = nums.length;
    let ops = 0, flip = 0;
    const flips = new Int32Array(n + 1);
    for (let i = 0; i < n - 2; i++) {
        flip ^= flips[i];
        if ((nums[i] ^ flip) === 0) {
            ops++;
            flip ^= 1;
            flips[i + 3] ^= 1;
        }
    }
    for (let i = n - 2; i < n; i++) {
        flip ^= flips[i];
        if ((nums[i] ^ flip) === 0) return -1;
    }
    return ops;
};
